# -*- coding: utf-8 -*-import cv2import numpy as npfrom pymycobot.mycobot import MyCobotfrom pymycobot.genre import Angleimport timeimport basicfrom GrabParams_2 import grabParamsimport mathimport rospyfrom geometry_msgs.msg import Twistrospy.init_node('movement', anonymous=True)pub = rospy.Publisher('cmd_vel', Twist, queue_size=1)rate = rospy.Rate(20)  # 20hzmove_cmd = Twist()# 优化后的颜色阈值（保持不变，因为当前设置合理）lower_blue = np.array([100, 43, 46])upper_blue = np.array([124, 255, 255])lower_red = np.array([170, 120, 120])upper_red = np.array([180, 255, 255])lower_yellow = np.array([22, 93, 0])upper_yellow = np.array([34, 255, 255])lower_green = np.array([35, 43, 35])upper_green = np.array([90, 255, 255])lower_purple = np.array([120, 43, 46])upper_purple = np.array([200, 255, 255])lower_orange = np.array([11, 43, 46])upper_orange = np.array([25, 255, 255])class OptimizedRobotArm:    def __init__(self):        self.mc = MyCobot(grabParams.usb_dev, grabParams.baudrate)        self.motion_num = 0        # 优化后的关键角度配置        self.angles = {            'initial':[-90.7, -28.12, -4.74, 52.2, -1.75, -50.88],            'pre_grasp': [-86.3, -40.78, -2.28, 50.97, -5.44, -48.16],  # 优化后的预抓取位置            'grasp': [-94.3, -36.82, -17.13, 62.22, 4.13, -41.92],  # 优化后的抓取位置            'lift': [-87.62, 30.05, -109.07, 82.44, -5.53, -48.51],  # 优化后的抬升位置            'place': [-89.56, -10.1, -101.86, 107.13, -5.27, -43.59],  # 优化后的放置位置            'home': [-90.7, -28.12, -4.74, 52.2, -1.75, -50.88]  # 优化后的 home 位置        }        # 优化后的速度配置        self.speeds = {            'fast': 70,  # 快速移动（空载时）65            'normal': 50,  # 正常速度            'slow': 40  # 慢速（抓取和放置时）30        }    def set_busy_status(self, busy=True):        """设置机械臂状态指示灯"""        if busy:            self.mc.set_color(0, 0, 255)  # 蓝色 - 忙碌        else:            self.mc.set_color(0, 255, 0)  # 绿色 - 空闲    def open_gripper(self, value=255, speed=30):        """打开夹爪"""        self.mc.set_gripper_value(value, speed)        time.sleep(1.5)    def close_gripper(self, value=35, speed=50):        """关闭夹爪"""        self.mc.set_gripper_value(value, speed)        time.sleep(1.5)    def move_to_position(self, position_name, speed=None):        """移动到指定位置"""        if speed is None:            speed = self.speeds['normal']        angles = self.angles[position_name]        self.mc.send_angles(angles, speed)        time.sleep(2)    def detect_object(self):        """视觉检测物体"""        cap = cv2.VideoCapture(2)        while True:            # 发布移动指令            move_cmd.linear.x = 0.02            move_cmd.linear.z = 0            pub.publish(move_cmd)            retval, frame = cap.read()            if not retval:                continue            # 检测逻辑（保持原有检测逻辑）            flag = 0            hsv = cv2.cvtColor(frame, cv2.COLOR_BGR2HSV)            # 创建各种颜色的掩码            masks = {                'blue': cv2.inRange(hsv, lower_blue, upper_blue),                'red': cv2.inRange(hsv, lower_red, upper_red),                'yellow': cv2.inRange(hsv, lower_yellow, upper_yellow),                'green': cv2.inRange(hsv, lower_green, upper_green),                'purple': cv2.inRange(hsv, lower_purple, upper_purple),                'orange': cv2.inRange(hsv, lower_orange, upper_orange)            }            # 检测每种颜色            for color, mask in masks.items():                contours, _ = cv2.findContours(mask, cv2.RETR_TREE, cv2.CHAIN_APPROX_SIMPLE)                for contour in contours:                    area = cv2.contourArea(contour)                    if self.is_valid_area(area, color):                        x, y, w, h = cv2.boundingRect(contour)                        cv2.rectangle(frame, (x, y), (x + w, y + h), (0, 255, 0), 2)                        if self.is_in_grasp_zone(x, y, color):                            flag = 1                            print("Detected {} object at ({}, {})".format(color, x, y))            cv2.imshow('Detection', frame)            if flag == 1:                break            if cv2.waitKey(1) & 0xFF == ord('q'):                break        # 停止移动        move_cmd.linear.x = 0        pub.publish(move_cmd)        cap.release()        cv2.destroyAllWindows()        return flag == 1    def is_valid_area(self, area, color):        """判断轮廓面积是否有效"""        area_ranges = {            'blue': (3000, 20000),            'red': (5000, 15000),            'yellow': (5000, 15000),            'green': (5000, 20000),            'purple': (5000, 15000),            'orange': (5000, 15000)        }        min_area, max_area = area_ranges.get(color, (5000, 15000))        return min_area <= area <= max_area    def is_in_grasp_zone(self, x, y, color):        """判断物体是否在抓取区域内"""        # 根据不同颜色调整抓取区域        zones = {            'blue': (300, 450, 190, 195),            'red': (300, 450, 140, 200),            'yellow': (300, 450, 140, 200),            'green': (300, 450, 170, 200),            'purple': (300, 450, 140, 200),            'orange': (350, 450, 140, 200)        }        x_min, x_max, y_min, y_max = zones.get(color, (300, 450, 140, 200))        return x_min <= x <= x_max and y_min <= y <= y_max    def grasp_and_place(self):        """优化的抓取和放置流程"""        print("Starting optimized grasp and place sequence...")        # 设置忙碌状态        self.set_busy_status(True)        # 步骤1: 打开夹爪并移动到预抓取位置        print("Step 1: Opening gripper and moving to pre-grasp position")        self.open_gripper()        self.move_to_position('pre_grasp', self.speeds['fast'])        # 步骤2: 下降到抓取位置        print("Step 2: Lowering to grasp position")        self.move_to_position('grasp', self.speeds['slow'])        # 步骤3: 抓取物体        print("Step 3: Grasping object")        self.close_gripper()        # 步骤4: 抬升到安全高度        print("Step 4: Lifting to safe height")        self.move_to_position('lift', self.speeds['normal'])        # 步骤5: 移动到放置位置        print("Step 5: Moving to place position")        self.move_to_position('place', self.speeds['fast'])        # 步骤6: 释放物体        print("Step 6: Releasing object")        self.open_gripper()        # 步骤7: 返回安全位置        print("Step 7: Returning to safe position")        self.move_to_position('lift', self.speeds['normal'])        self.move_to_position('home', self.speeds['fast'])        # 设置空闲状态        self.set_busy_status(False)        print("Grasp and place sequence completed!")        self.motion_num += 1    def run(self):        """主运行循环"""        try:            # 初始化到起始位置            self.move_to_position('initial', self.speeds['normal'])            while True:                if self.motion_num >= 3:                    break                print("Starting motion cycle {}".format(self.motion_num + 1))                # 检测物体                if self.detect_object():                    # 执行抓取和放置                    self.grasp_and_place()                else:                    print("No object detected, continuing...")                    time.sleep(1)            # 返回最终位置            self.move_to_position('home', self.speeds['normal'])            print("All motion cycles completed!")        except KeyboardInterrupt:            print("Program interrupted by user")        except Exception as e:            print("Error occurred: {}".format(e))        finally:            self.set_busy_status(False)if __name__ == "__main__":    robot_arm = OptimizedRobotArm()    robot_arm.run()